cd /workspace/youtube && cat > /tmp/repro-youtube-theme-transition.js <<'EOF'
const assert = require('assert');
const fs = require('fs');
const vm = require('vm');

function loadThemeSkeleton(currentTheme) {
  const context = {
    extension: { skeleton: { main: { layers: { section: {} } } } },
    satus: { storage: { get: key => (key === 'theme' ? currentTheme : undefined) } }
  };

  vm.runInNewContext(
    fs.readFileSync('/workspace/youtube/menu/skeleton-parts/themes.js', 'utf8'),
    context,
    { filename: 'menu/skeleton-parts/themes.js' }
  );

  return context.extension.skeleton.main.layers.section.themes.on.click.section;
}

function radioItems(section) {
  return Object.keys(section)
    .map(key => typeof section[key] === 'function' ? section[key]() : section[key])
    .filter(item => item && item.radio)
    .map(item => ({ text: item.text, value: item.radio.value, checked: !!item.radio.checked }));
}

function defaultValue(items) {
  let defValue;

  for (const item of items) {
    if (!defValue && item.value) {
      defValue = item.value;
    } else if (item.checked) {
      defValue = item.value;
    }
  }

  return defValue;
}

function simulateClick(currentTheme, clickedValue) {
  const items = radioItems(loadThemeSkeleton(currentTheme));
  const defValue = defaultValue(items);
  const operations = [];

  if (currentTheme !== clickedValue) {
    operations.push(['set', clickedValue]);
  }

  if (clickedValue === defValue) {
    operations.push(['remove', undefined]);
  }

  const finalCoalescedValue = operations.length ? operations[operations.length - 1][1] : currentTheme;
  return { items, defValue, operations, finalCoalescedValue };
}

function pageStillDarkIfOnlyFinalValueArrives(finalValue) {
  const documentElement = {
    dark: true,
    setAttribute(name) { if (name === 'dark') this.dark = true; },
    removeAttribute(name) { if (name === 'dark') this.dark = false; },
    hasAttribute(name) { return name === 'dark' && this.dark; }
  };

  // Mirrors the relevant part of ImprovedTube.setTheme(): only 'light' removes dark.
  switch (finalValue) {
    case 'dark':
      documentElement.setAttribute('dark', '');
      break;
    case 'light':
    case 'dawn':
    case 'sunset':
    case 'night':
    case 'plain':
    case 'desert':
      documentElement.removeAttribute('dark');
      break;
  }

  return documentElement.hasAttribute('dark');
}

const darkToLight = simulateClick('dark', 'light');
console.log('Dark -> Light simulation:', JSON.stringify(darkToLight, null, 2));
assert.deepStrictEqual(darkToLight.operations, [['set', 'light'], ['remove', undefined]], 'BUG: current menu should set then remove theme when clicking Light from Dark');
assert.strictEqual(pageStillDarkIfOnlyFinalValueArrives(darkToLight.finalCoalescedValue), true, 'BUG: coalesced remove leaves dark attribute intact');

const blackToLight = simulateClick('black', 'light');
console.log('Black -> Light simulation:', JSON.stringify(blackToLight, null, 2));
assert.deepStrictEqual(blackToLight.operations, [['set', 'light'], ['remove', undefined]], 'Light is treated as default outside Dark too');
assert.strictEqual(pageStillDarkIfOnlyFinalValueArrives(blackToLight.finalCoalescedValue), true, 'Harness starts with dark attr; real non-dark themes do not depend on removing it');

console.log('Reproduction confirmed: Dark -> Light can remove storage before page applies light cleanup.');
EOF
